script.text:

function active$AMPerformanceInfor(f) {
  f.add_onResponseComplete(on$AMPerformanceInfor$ResponseComplete);
  f._tabContainer.add_activeTabChanged(onChange$Voucher$Tab);
  f._tabContainer._loaded = true;
  set$Voucher$DefaultValue(f);
  if (f._action != 'View') {
    var c = (f._language == 'v' ? '' : '2');
    f.setReadOnlyFields('nam_cv,nam_lv,ngay_vao_cty,bac_quan_ly,ten_bp' + c + ',ten_vtr' + c);
  }
}
function scatter$AMPerformanceInfor(f) {
  set$Voucher$DefaultValue(f);
  if (f._action == 'View' || f._action == 'Edit') {
    var o = f.getItem('d01').field;
    o.AllowContain = false;
    o.FilterSource = 'Tidy';
  }
}
function close$AMPerformanceInfor(f) {
  try {f.remove_onResponseComplete(on$AMPerformanceInfor$ResponseComplete)} catch (ex) {}
  if (f._tabContainer) try {f._tabContainer.remove_activeTabChanged(onChange$Voucher$Tab);} catch (ex) {}
}

function onChange$Voucher$Tab(sender, e) {sender.parentForm.focusWhenTabChanged(['d01', 'yk_nv', 'yk_ql_tt', 'yk_ql_cc']);}
function on$AMPerformanceInfor$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Appraisee':
      f.setItemControlBehavior('stt_rec_nv', result[0].Value, true);
      f.setItemControlBehavior('ten_bp%l', result[1].Value, true);
      f.setItemControlBehavior('ten_vtr%l', result[2].Value, true);
      f.setItemControlBehavior('bac_quan_ly', result[3].Value, true);
      f.setItemValue('ngay_vao_cty', result[4].Value);
      f.setItemValue('nam_lv', result[5].Value);
      f.setItemValue('nam_cv', result[6].Value);
      if (result[7].Value && result[8].Value) {
        f.setItemControlBehavior('stt_rec_ndg', result[7].Value, true);
        f.setItemControlBehavior('ma_nv_dg', result[8].Value, result[9].Value, true);
        f.live(f.getItem('ma_nv_dg'));
      }
      break;
    case 'Appraiser':
      f.setItemControlBehavior('stt_rec_ndg', result[0].Value, true);
      break;
    default:
      break;
  }
}

function set$Voucher$DefaultValue(f) {
  if (f._action == 'New') {
    var d = new Date();
    f.setItemValue('ngay_dg', d);
    f.setItemValue('ma_ky', d.getMonth() + 1);
    f.setItemValue('nam', d.getFullYear());
    f.live(f.getItem('ma_ky'));
  }
}
function onchange$AMPerformanceInfor$EmployeeID(o) {o.parentForm.request('Appraiser', 'Appraiser', [['ma_nv', 'String', o.value]]);}
function onchange$AMPerformanceInfor$Appraisee$EmployeeID(o) {
  var f = o.parentForm;
  f.request('Appraisee', 'Appraisee', [['ma_nv', 'String', f.getItemValue('ma_nv')], ['ngay_dg', 'Date', f.getItemValue('ngay_dg')]]);  
}
